	}))
	defer ts.Close()

	entry := urlFetchEntry()
	result := entry.Execute(context.Background(), provider.ToolCall{ID: "uf-empty-body", Arguments: map[string]string{"url": ts.URL}}, ExecContext{})

	if result.IsError {
